// ESP32 Button + LED PWM
// ======================
// Press the button to toggle the LED on/off.
// When on, potentiometer controls brightness via LEDC PWM.
//
// Circuit:
//   GPIO15 <- Button -> GND   (INPUT_PULLUP)
//   GPIO34 <- Pot SIG          (ADC, input-only pin)
//   GPIO18 -> 220R -> Yellow LED -> GND  (LEDC PWM)

#include <Arduino.h>

// Pin assignments
const int BUTTON_PIN = 15;
const int POT_PIN    = 34;   // Input-only on ESP32
const int LED_PIN    = 18;

// LEDC PWM config
const int LEDC_CH   = 0;
const int LEDC_FREQ = 5000;
const int LEDC_RES  = 8;     // 0-255

bool ledEnabled = false;
bool lastBtnState = HIGH;
unsigned long lastDebounce = 0;
const unsigned long DEBOUNCE_MS = 50;

void setup() {
  Serial.begin(115200);
  delay(200);

  Serial.println("==========================");
  Serial.println("  ESP32 Button + LED PWM");
  Serial.println("==========================");
  Serial.println();

  pinMode(BUTTON_PIN, INPUT_PULLUP);
  analogReadResolution(12);

  ledcSetup(LEDC_CH, LEDC_FREQ, LEDC_RES);
  ledcAttachPin(LED_PIN, LEDC_CH);
  ledcWrite(LEDC_CH, 0);

  Serial.println("Press button to toggle LED.");
  Serial.println("Turn pot to adjust brightness.");
  Serial.println("---");
}

void loop() {
  // Debounced button toggle
  bool btnState = digitalRead(BUTTON_PIN);
  if (btnState != lastBtnState && (millis() - lastDebounce) > DEBOUNCE_MS) {
    lastDebounce = millis();
    if (btnState == LOW) {
      ledEnabled = !ledEnabled;
      Serial.print("LED toggled: ");
      Serial.println(ledEnabled ? "ON" : "OFF");
    }
  }
  lastBtnState = btnState;

  // Read potentiometer (12-bit: 0-4095)
  int potRaw = analogRead(POT_PIN);
  int brightness = map(potRaw, 0, 4095, 0, 255);

  // Apply PWM
  if (ledEnabled) {
    ledcWrite(LEDC_CH, brightness);
  } else {
    ledcWrite(LEDC_CH, 0);
  }

  // Periodic telemetry
  static unsigned long lastPrint = 0;
  if (millis() - lastPrint >= 250) {
    lastPrint = millis();
    Serial.print("btn=");
    Serial.print(btnState == LOW ? "DOWN" : "UP");
    Serial.print("  led=");
    Serial.print(ledEnabled ? "ON" : "OFF");
    Serial.print("  pot=");
    Serial.print(potRaw);
    Serial.print("  pwm=");
    Serial.println(ledEnabled ? brightness : 0);
  }

  delay(10);
}
